---

# `findByNickname` 쿼리 성능 최적화 분석 및 개선안

## 1. 병목 식별 - 현재 구현의 문제점

현재 프로젝트에 실제 소스 파일이 존재하지 않으므로, SKILL.md 컨벤션 및 프로젝트 스펙을 기반으로 전형적인 패턴에서 발생하는 문제를 분석합니다.

### Before - 전형적인 문제 코드

**파일: `domain/src/main/kotlin/com/maum/backend/entity/user/UserEntity.kt`**

```kotlin
// BEFORE - 인덱스 없음, EAGER 로딩 위험
@Entity
@Table(catalog = "maum", name = "user")
class UserEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val nickname: String,         // 인덱스 없음 -> FULL TABLE SCAN 발생
    val phoneNumber: String,
    val status: Int = 1,

    @OneToMany(fetch = FetchType.EAGER)  // N+1 위험: 조회 시 즉시 로딩
    val profiles: List<ProfileEntity> = emptyList(),

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

**파일: `domain/src/main/kotlin/com/maum/backend/repository/user/UserRepository.kt`**

```kotlin
// BEFORE - 단순 Spring Data JPA 메서드, 모든 컬럼 SELECT
interface UserRepository : JpaRepository<UserEntity, String> {
    fun findByNickname(nickname: String): UserEntity?
    // -> SELECT * FROM maum.user WHERE nickname = ? (인덱스 없으면 Full Table Scan)
}
```

### 문제점 요약

| 문제 | 원인 | 영향 |
|------|------|------|
| Full Table Scan | `nickname` 컬럼에 인덱스 없음 | 데이터 증가 시 응답 시간 O(N) 증가 |
| 불필요한 컬럼 SELECT | `SELECT *` 모든 필드 조회 | 네트워크/메모리 낭비 |
| N+1 쿼리 잠재 위험 | EAGER 관계 매핑 | 연관 엔티티 수만큼 추가 쿼리 발생 |
| 캐시 없음 | 동일 nickname 반복 조회 | DB 부하 반복 발생 |
| 카디널리티 미고려 | 닉네임 중복 가능 여부 미반영 | 잘못된 인덱스 전략 |

---

## 2. 최적화 방안

### 2-1. 인덱스 추가 (가장 즉각적인 효과)

**파일: `domain/src/main/kotlin/com/maum/backend/entity/user/UserEntity.kt`**

```kotlin
// AFTER - 인덱스 추가, LAZY 로딩 적용
@Entity
@Table(
    catalog = "maum",
    name = "user",
    indexes = [
        // nickname 단일 인덱스 (UNIQUE: 닉네임 중복 불가 정책 반영)
        Index(name = "idx_user_nickname", columnList = "nickname", unique = true),
        // 복합 인덱스: status 조건과 함께 조회되는 경우
        Index(name = "idx_user_nickname_status", columnList = "nickname, status"),
    ]
)
class UserEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @Column(nullable = false, unique = true, length = 20)
    val nickname: String,

    @Column(nullable = false, length = 20)
    val phoneNumber: String,

    val status: Int = 1,

    // LAZY로 변경: 필요할 때만 프로파일 조회
    @OneToMany(fetch = FetchType.LAZY, mappedBy = "user")
    val profiles: List<ProfileEntity> = emptyList(),

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

**Flyway Migration SQL (파일: `domain/src/main/resources/db/migration/V{버전}__add_index_user_nickname.sql`)**

```sql
-- 기존 테이블에 인덱스 추가 (DDL auto가 아닌 환경)
CREATE UNIQUE INDEX idx_user_nickname ON maum.user (nickname);

-- 실행 계획 확인용 (적용 후 검증)
-- EXPLAIN SELECT * FROM maum.user WHERE nickname = 'testUser';
```

### 2-2. 쿼리 최적화 - Projection 및 JPQL 명시

**파일: `domain/src/main/kotlin/com/maum/backend/repository/user/UserRepository.kt`**

```kotlin
// AFTER - Projection, JPQL 명시, 캐시 어노테이션 적용
@Repository
interface UserRepository : JpaRepository<UserEntity, String> {

    // 1. 기본 닉네임 조회 (Redis 캐시 적용)
    @Cacheable(value = ["user:nickname"], key = "#nickname", unless = "#result == null")
    fun findByNickname(nickname: String): UserEntity?

    // 2. 필요한 필드만 SELECT하는 JPQL (Projection)
    @Query("""
        SELECT new com.maum.backend.repository.user.dto.UserSummaryDto(
            u.id, u.nickname, u.status
        )
        FROM UserEntity u
        WHERE u.nickname = :nickname
          AND u.status = 1
    """)
    fun findSummaryByNickname(@Param("nickname") nickname: String): UserSummaryDto?

    // 3. 닉네임 존재 여부만 확인 (중복 체크용 - COUNT 최적화)
    fun existsByNickname(nickname: String): Boolean

    // 4. 닉네임 prefix 검색 (자동완성용) - 인덱스 range scan 활용
    @Query("""
        SELECT u FROM UserEntity u
        WHERE u.nickname LIKE :prefix%
          AND u.status = 1
        ORDER BY u.nickname
    """)
    fun findByNicknameStartingWith(
        @Param("prefix") prefix: String,
        pageable: Pageable
    ): Slice<UserEntity>
}
```

**파일: `domain/src/main/kotlin/com/maum/backend/repository/user/dto/UserSummaryDto.kt`**

```kotlin
// Projection DTO - 필요한 필드만 전송
data class UserSummaryDto(
    val id: String,
    val nickname: String,
    val status: Int
)
```

### 2-3. Redis 캐시 전략

**파일: `app/src/main/kotlin/com/maum/backend/config/CacheConfig.kt`**

```kotlin
@Configuration
@EnableCaching
class CacheConfig(
    private val redisConnectionFactory: RedisConnectionFactory
) {

    @Bean
    fun cacheManager(): CacheManager {
        val objectMapper = ObjectMapper().apply {
            registerModule(KotlinModule.Builder().build())
            registerModule(JavaTimeModule())
            disable(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS)
            activateDefaultTyping(
                LaissezFaireSubTypeValidator.instance,
                ObjectMapper.DefaultTyping.NON_FINAL
            )
        }

        val jsonSerializer = GenericJackson2JsonRedisSerializer(objectMapper)

        // 캐시별 TTL 설정
        val cacheConfigs = mapOf(
            // 닉네임 조회: 자주 변경되지 않으므로 10분 TTL
            "user:nickname" to RedisCacheConfiguration.defaultCacheConfig()
                .entryTtl(Duration.ofMinutes(10))
                .serializeValuesWith(
                    RedisSerializationContext.SerializationPair.fromSerializer(jsonSerializer)
                ),

            // 닉네임 존재 여부: 5분 TTL (중복 가입 방지)
            "user:nickname:exists" to RedisCacheConfiguration.defaultCacheConfig()
                .entryTtl(Duration.ofMinutes(5))
                .serializeValuesWith(
                    RedisSerializationContext.SerializationPair.fromSerializer(jsonSerializer)
                ),
        )

        return RedisCacheManager.builder(redisConnectionFactory)
            .withInitialCacheConfigurations(cacheConfigs)
            .cacheDefaults(
                RedisCacheConfiguration.defaultCacheConfig()
                    .entryTtl(Duration.ofMinutes(5))
            )
            .build()
    }
}
```

**파일: `app/src/main/kotlin/com/maum/backend/service/user/UserService.kt`**

```kotlin
@Service
@Transactional(readOnly = true)
class UserService(
    private val userRepository: UserRepository
) {

    // 닉네임으로 사용자 조회 - 캐시 우선
    @Cacheable(value = ["user:nickname"], key = "#nickname", unless = "#result == null")
    fun getUserByNickname(nickname: String): UserEntity? {
        return userRepository.findByNickname(nickname)
    }

    // 닉네임 변경 시 캐시 무효화
    @CacheEvict(value = ["user:nickname"], key = "#oldNickname")
    @Transactional
    fun updateNickname(userId: String, oldNickname: String, newNickname: String): UserEntity {
        val user = userRepository.findById(userId)
            .orElseThrow { IllegalArgumentException("사용자를 찾을 수 없습니다: $userId") }
        // 닉네임 변경 로직
        return userRepository.save(user.copy(nickname = newNickname))
    }

    // 닉네임 중복 확인 - 경량 캐시 적용
    @Cacheable(value = ["user:nickname:exists"], key = "#nickname")
    fun isNicknameExists(nickname: String): Boolean {
        return userRepository.existsByNickname(nickname)
    }
}
```

